  const bytes = seedBytes(seedHex, count)
  const remaining = Array.from({ length: N }, (_, i) => i + 1)
  const picks = []
  for (let k = 0; k < count; k++) {
    const idx = bytes[k] % remaining.length
    picks.push(remaining[idx])
    remaining.splice(idx, 1)
  }
